-- Validation Query 4: Check function parameters
SELECT 
    p.proname as function_name,
    p.pronargs as parameter_count,
    array_agg(pp.argname ORDER BY pp.argnumber) as parameter_names,
    array_agg(pp.argtype::regtype ORDER BY pp.argnumber) as parameter_types
FROM pg_proc p
LEFT JOIN pg_parameter pp ON p.oid = pp.oid
WHERE p.proname IN ('nearby_hospitals', 'nearby_ambulances', 'get_entity_id')
    AND p.pronamespace = 'public'::regnamespace
GROUP BY p.proname, p.pronargs
ORDER BY p.proname;

